    SELECT thc.*,
           twi.workplace_nm,
           thc.checklist_start || ' ~ ' || thc.checklist_end  AS checklist_time
     FROM esg.tb_hazmat_checklist thc
LEFT JOIN esg.tb_workplace_info twi
       ON twi.workplace_id = thc.workplace_id
    WHERE 1 = 1
      AND thc.comp_id = #{compId}
      AND thc.write_year = #{writeYear}
      AND thc.doc_type = #{docType}
      AND thc.doc_no = #{docNo}

